#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;unistd.h&gt;
#include &lt;sys/wait.h&gt;

int main() {
    int num_children = 5;

    // 1. SPawning Phase
    for (int i = 0; i < num_children; i++) {
        pid_t pid = fork();
        if (pid == 0) {
            // CHILD PROCESS
            printf("[Child %d] Executing heavy computation...\n", getpid());
            sleep(1); // Simulate work

            // Exit with a unique code (0-255) based on their loop index
            exit(100 + i); 
        }
    }

    // 2. REAPING PHASE (Parent executes this)
    // We must collect exactly 5 exit statuses.
    for (int i = 0; i < num_children; i++) {
        int wstatus;
        // Passing -1 means "Wait for ANY of my children to die"
        pid_t dead_child = waitpid(-1, &wstatus, 0);

        if (dead_child > 0) {
            if (WIFEXITED(wstatus)) {
                // Extract the clean 8-bit exit code
                int exit_code = WEXITSTATUS(wstatus);
                printf("[Parent] Reaped Child %d. Exit Code: %d\n", dead_child, exit_code);
            } else if (WIFSIGNALED(wstatus)) {
                // The child was violently killed by a signal
                int sig = WTERMSIG(wstatus);
                printf("[Parent] Child %d crashed. Signal: %d\n", dead_child, sig);
            }
        }
    }

    printf("[Parent] All children successfully reaped. Exiting.\n");
    return 0;
}

